<template>
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>VIDEOS DE LA CARRERA</h1>
          </div>

          <h4>
            <router-link to="/">INICIO</router-link>
          </h4>
          <h5>VIDEOS</h5>
        </div>
      </div>
    </div>
  </div>

  <div class="container blog-wrapper padding-lg">
    <div class="col-12 justify-content-center" v-if="Videos.length == 0">
      <h2>SIN VIDEOS</h2>
    </div>

    <div v-else class="row news-listing">
      <div class="col-sm-8 blog-left">
        <ul
          v-for="(vid, id_vid) of Videos"
          :key="id_vid"
          class="col-xs-6 col-sm-6 grid-item"
        >
          <li>
            <iframe
              :src="vid.video_enlace"
              frameborder="0"
              style="border-radius: 5px"
            />
            <br />

            <ul class="post-detail">
              <li><span class="label">VIDEOS</span></li>
            </ul>
            <h5>
              <!-- <router-link :to="'/detalleVideo/' + vid.video_id"> -->
              {{ vid.video_titulo }}
              <!-- </router-link> -->
            </h5>
            <!-- <router-link :to="'/detalleVideo/' + vid.video_id" class="readmore-text">
              Read More
            </router-link> -->
          </li>
        </ul>
      </div>

      <div class="col-sm-4">
        <sidebar-custom></sidebar-custom>
      </div>
    </div>
  </div>
</template>

<script>
import SidebarCustom from "@/components/SidebarCustom.vue";
import { mapState } from "vuex";
export default {
  name: "VideosView",
  data() {
    return {
      Videos: [],
      search: "",
      searchGet: false,
      searchValues: [],

      NUM_RESULTS: 4,
      pag: 1,
      pager: 0,
    };
  },
  computed: {
    ...mapState(["url_api"]),
  },
  components: {
    SidebarCustom,
  },
  methods: {
    async getVideosAll() {
      try {
        let res = await this.axios.get(
          "/api/VideosAll/" + process.env.VUE_APP_ID_INSTITUCION
        );
        this.Videos = [];
        res.data.forEach((video) => {
          if (video.video_estado == "1") {
            this.Videos.push(video);
          }
        });
        this.pager = this.Videos.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    dmy(fecha) {
      const meses = [
        "enero",
        "febrero",
        "marzo",
        "abril",
        "mayo",
        "junio",
        "julio",
        "agosto",
        "septiembre",
        "octubre",
        "noviembre",
        "diciembre",
      ];
      let fechaCadena = fecha.substr(0, 10);
      let fechaArray = fechaCadena.split("-");
      return (
        fechaArray[2] +
        " de " +
        meses[parseInt(fechaArray[1]) - 1] +
        " de " +
        fechaArray[0]
      );
    },
    buscar() {
      if (this.search != "") {
        this.searchGet = true;

        this.searchValues = [];
        this.Videos.forEach((vid) => {
          if (
            vid.video_titulo.toUpperCase().includes(this.search.toUpperCase())
          ) {
            this.searchValues.push(vid);
          }
        });
      } else {
        this.searchGet = false;
      }
    },
  },
  mounted() {
    this.$store.commit("loadOn");
    this.getVideosAll();
  },
  created() {
    this.$store.commit("loadOn");
    this.getVideosAll();
  },
};
</script>
